def max_product_subarray(nums):
    best = high = low = nums[0]
    for n in nums[1:]:
        high, low = max(n, high * n, low * n), min(n, high * n, low * n)
        best = max(best, high)
    return best

def kadane_indices(nums):
    best_sum = cur_sum = nums[0]
    best_start = best_end = start = 0
    for i, n in enumerate(nums[1:], 1):
        if cur_sum + n < n:
            cur_sum, start = n, i
        else:
            cur_sum += n
        if cur_sum > best_sum:
            best_sum, best_start, best_end = cur_sum, start, i
    return best_start, best_end, best_sum

def spiral_order(matrix):
    result = []
    while matrix:
        result += matrix.pop(0)
