def flood_fill(grid, r, c, new_value):
    old = grid[r][c]
    if old == new_value:
        return grid
    stack = [(r, c)]
    while stack:
        x, y = stack.pop()
        if 0 <= x < len(grid) and 0 <= y < len(grid[0]) and grid[x][y] == old:
            grid[x][y] = new_value
            stack += [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
    return grid

def island_count(grid):
    count = 0
    for r, row in enumerate(grid):
        for c, value in enumerate(row):
            if value != 1:
                continue
            count += 1
            stack = [(r, c)]
            while stack:
                x, y = stack.pop()
                if 0 <= x < len(grid) and 0 <= y < len(grid[0]) and grid[x][y] == 1:
                    grid[x][y] = 0
                    stack += [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
    return count

def parse_csv_line(line):
    cells, cell, quoted = [], [], False
    for ch in line:
        if ch == '"':
            quoted = not quoted
        elif ch == ',' and not quoted:
            cells.append(''.join(cell))
            cell = []
        else:
            cell.append(ch)
    cells.append(''.join(cell))
    return cells

