    total = 0
    for i, ch in enumerate(s):
        value = values[ch]
        total += -value if i + 1 < len(s) and value < values[s[i + 1]] else value
    return total

def int_to_roman(num):
    pairs = [(1000, 'M'), (900, 'CM'), (500, 'D'), (400, 'CD'), (100, 'C'), (90, 'XC'), (50, 'L'), (40, 'XL'), (10, 'X'), (9, 'IX'), (5, 'V'), (4, 'IV'), (1, 'I')]
    result = []
    for value, symbol in pairs:
        count, num = divmod(num, value)
        result.append(symbol * count)
    return ''.join(result)

def balanced_brackets(text):
    pairs = {')': '(', ']': '[', '}': '{'}
    stack = []
    for ch in text:
        if ch in pairs.values():
            stack.append(ch)
        elif ch in pairs and (not stack or stack.pop() != pairs[ch]):
            return False
    return not stack

def shunting_yard(tokens):
    prec = {'+': 1, '-': 1, '*': 2, '/': 2}
    output, ops = [], []
    for token in tokens:
        if token not in prec and token not in '()':
            output.append(token)
        elif token == '(':
            ops.append(token)
        elif token == ')':
            while ops[-1] != '(':
                output.append(ops.pop())
            ops.pop()
        else:
            while ops and ops[-1] in prec and prec[ops[-1]] >= prec[token]:
                output.append(ops.pop())
            ops.append(token)
    return output + ops[::-1]

def evaluate_postfix(tokens):
    stack = []
    for token in tokens:
        if token in {'+', '-', '*', '/'}:
            b, a = stack.pop(), stack.pop()
            stack.append({'+': a + b, '-': a - b, '*': a * b, '/': a / b}[token])
        else:
            stack.append(int(token))
    return stack[-1]

def binary_tree_levels(root):
    if not root:
        return []
    levels, queue = [], [root]
    while queue:
        levels.append([node.value for node in queue])
        queue = [child for node in queue for child in (node.left, node.right) if child]
    return levels

def tree_height(root):
    if not root:
        return 0
    return 1 + max(tree_height(root.left), tree_height(root.right))

def is_bst(root, low=float('-inf'), high=float('inf')):
    if not root:
        return True
    return low < root.value < high and is_bst(root.left, low, root.value) and is_bst(root.right, root.value, high)

def trie_insert_all(words):
    root = {}
    for word in words:
        node = root
        for ch in word:
            node = node.setdefault(ch, {})
        node[''] = True
    return root

def trie_contains(trie, word):
    node = trie
    for ch in word:
        if ch not in node:
            return False
        node = node[ch]
    return '' in node

def kmp_prefix_table(pattern):
    table = [0] * len(pattern)
    j = 0
    for i in range(1, len(pattern)):
        while j and pattern[i] != pattern[j]:
            j = table[j - 1]
        if pattern[i] == pattern[j]:
            j += 1
            table[i] = j
    return table

def kmp_search(text, pattern):
    if not pattern:
        return list(range(len(text) + 1))
    table = [0] * len(pattern)
    j = 0
    for i in range(1, len(pattern)):
        while j and pattern[i] != pattern[j]:
            j = table[j - 1]
        if pattern[i] == pattern[j]:
            j += 1
            table[i] = j
    result, j = [], 0
    for i, ch in enumerate(text):
        while j and ch != pattern[j]:
            j = table[j - 1]
        if ch == pattern[j]:
            j += 1
            if j == len(pattern):
                result.append(i - j + 1)
                j = table[j - 1]
    return result

def quickselect(nums, k):
    pivot = nums[len(nums) // 2]
    lows = [n for n in nums if n < pivot]
    highs = [n for n in nums if n > pivot]
    pivots = [n for n in nums if n == pivot]
    if k < len(lows):
        return quickselect(lows, k)
    if k < len(lows) + len(pivots):
        return pivot
    return quickselect(highs, k - len(lows) - len(pivots))

def next_permutation(nums):
    nums = list(nums)
    i = len(nums) - 2
    while i >= 0 and nums[i] >= nums[i + 1]:
        i -= 1
    if i >= 0:
        j = len(nums) - 1
        while nums[j] <= nums[i]:
            j -= 1
        nums[i], nums[j] = nums[j], nums[i]
    nums[i + 1:] = reversed(nums[i + 1:])
    return nums

def reservoir_sample_one(items):
    import random
    chosen = None
    for i, item in enumerate(items, 1):
        if random.randrange(i) == 0:
            chosen = item
    return chosen

def lru_put(cache, order, key, value, capacity):
    if key in cache:
        order.remove(key)
    elif len(cache) >= capacity:
        old = order.pop(0)
        del cache[old]
    cache[key] = value
    order.append(key)
    return cache, order

def rate_limit_allowed(times, now, window, limit):
    times[:] = [t for t in times if now - t < window]
    if len(times) >= limit:
        return False
    times.append(now)
    return True

def polynomial_eval(coefficients, x):
    result = 0
    for coefficient in coefficients:
        result = result * x + coefficient
    return result

def stable_partition(items, predicate):
    yes, no = [], []
    for item in items:
        (yes if predicate(item) else no).append(item)
    return yes + no

def rolling_hashes(text, size, base=257, mod=1000000007):
    if size <= 0 or size > len(text):
        return []
    power = pow(base, size - 1, mod)
    value = 0
    for ch in text[:size]:
        value = (value * base + ord(ch)) % mod
    hashes = [value]
    for i in range(size, len(text)):
        value = ((value - ord(text[i - size]) * power) * base + ord(text[i])) % mod
        hashes.append(value)
    return hashes

def convex_hull_points(points):
    points = sorted(set(points))
    if len(points) <= 1:
        return points
    def cross(o, a, b):
        return (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])
    lower = []
    for p in points:
        while len(lower) >= 2 and cross(lower[-2], lower[-1], p) <= 0:
            lower.pop()
        lower.append(p)
    upper = []
    for p in reversed(points):
        while len(upper) >= 2 and cross(upper[-2], upper[-1], p) <= 0:
            upper.pop()
        upper.append(p)
    return lower[:-1] + upper[:-1]

def z_algorithm(text):
    z = [0] * len(text)
    left = right = 0
    for i in range(1, len(text)):
        if i <= right:
            z[i] = min(right - i + 1, z[i - left])
        while i + z[i] < len(text) and text[z[i]] == text[i + z[i]]:
            z[i] += 1
        if i + z[i] - 1 > right:
            left, right = i, i + z[i] - 1
    return z

def manacher_lengths(text):
    radii = [0] * len(text)
    left, right = 0, -1
    for i in range(len(text)):
        k = 1 if i > right else min(radii[left + right - i], right - i + 1)
        while i - k >= 0 and i + k < len(text) and text[i - k] == text[i + k]:
            k += 1
        radii[i] = k
        if i + k - 1 > right:
            left, right = i - k + 1, i + k - 1
    return radii

def union_find_groups(items, pairs):
    parent = {x: x for x in items}
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    for a, b in pairs:
        parent[find(a)] = find(b)
    groups = {}
    for item in items:
        groups.setdefault(find(item), []).append(item)
    return list(groups.values())

def bellman_ford(nodes, edges, start):
    dist = {node: float('inf') for node in nodes}
    dist[start] = 0
    for _ in range(len(nodes) - 1):
        changed = False
        for a, b, w in edges:
            if dist[a] + w < dist[b]:
                dist[b] = dist[a] + w
                changed = True
        if not changed:
            break
    return None if any(dist[a] + w < dist[b] for a, b, w in edges) else dist

def floyd_warshall(matrix):
    dist = [row[:] for row in matrix]
    n = len(dist)
    for k in range(n):
        for i in range(n):
            for j in range(n):
                dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
    return dist

def mst_kruskal_weight(nodes, edges):
    parent = {node: node for node in nodes}
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    total = 0
    for weight, a, b in sorted(edges):
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb
            total += weight
    return total

def h_index(citations):
    citations = sorted(citations, reverse=True)
    h = 0
    for i, count in enumerate(citations, 1):
        if count >= i:
            h = i
    return h

def factorial(n):
    result = 1
    for k in range(2, n + 1):
        result *= k
    return result

def gcd(a, b):
    while b:
        a, b = b, a % b
    return abs(a)

def lcm(a, b):
    from math import gcd
    return abs(a * b) // gcd(a, b) if a and b else 0

def is_prime(n):
    if n < 2:
        return False
    return all(n % d for d in range(2, int(n ** .5) + 1))

def fibonacci(n):
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

def is_perfect_square(n):
    from math import isqrt
    return n >= 0 and isqrt(n) ** 2 == n

def integer_sqrt(n):
    from math import isqrt
    return isqrt(n)

def weighted_average(values, weights):
    total = sum(weights)
    return sum(v * w for v, w in zip(values, weights)) / total

def running_sum(nums):
    from itertools import accumulate
    return list(accumulate(nums))

def rotate_left(items, k):
    if not items:
        return []
    k %= len(items)
    return items[k:] + items[:k]

def rotate_right(items, k):
    if not items:
        return []
    k %= len(items)
    return items[-k:] + items[:-k]

def interleave(a, b):
    result = []
    for pair in zip(a, b):
        result.extend(pair)
    return result + a[len(b):] + b[len(a):]

def partition(items, predicate):
    yes, no = [], []
    for x in items:
        (yes if predicate(x) else no).append(x)
    return yes, no

def diagonal_sums(matrix):
    n = len(matrix)
    return sum(matrix[i][i] for i in range(n)), sum(matrix[i][~i] for i in range(n))

def char_frequency(text):
    from collections import Counter
    return dict(Counter(text))

def first_unique_char(text):
    from collections import Counter
    counts = Counter(text)
    return next((c for c in text if counts[c] == 1), '')

def common_prefix(strings):
    if not strings:
        return ''
    first, last = min(strings), max(strings)
    i = 0
    while i < min(len(first), len(last)) and first[i] == last[i]:
        i += 1
    return first[:i]

def common_suffix(strings):
    if not strings:
        return ''
    first, last = min(s[::-1] for s in strings), max(s[::-1] for s in strings)
    i = 0
    while i < min(len(first), len(last)) and first[i] == last[i]:
        i += 1
    return first[:i][::-1]

def is_anagram(a, b):
    from collections import Counter
    return Counter(a) == Counter(b)

def snake_to_camel(name):
    first, *rest = name.split('_')
    return first + ''.join(word.title() for word in rest)

def camel_to_snake(name):
    import re
    return re.sub(r'(?<!^)(?=[A-Z])', '_', name).lower()

def run_length_encode(text):
    from itertools import groupby
    return [(c, len(list(g))) for c, g in groupby(text)]

def rotate_string(text, k):
    if not text:
        return ''
    k %= len(text)
    return text[k:] + text[:k]

def balanced_parentheses(text):
    depth = 0
    for c in text:
        depth += (c == '(') - (c == ')')
        if depth < 0:
            return False
    return depth == 0

def caesar_cipher(text, shift):
    def f(c):
        base = ord('A' if c.isupper() else 'a')
        return chr((ord(c) - base + shift) % 26 + base) if c.isalpha() and c.isascii() else c
    return ''.join(map(f, text))

def strip_punctuation(text):
    import string
    return text.translate(str.maketrans('', '', string.punctuation))

def binary_search(nums, target):
    lo, hi = 0, len(nums)
    while lo < hi:
        mid = (lo + hi) // 2
        if nums[mid] < target:
            lo = mid + 1
        else:
            hi = mid
    return lo if lo < len(nums) and nums[lo] == target else -1

def lower_bound(nums, target):
    from bisect import bisect_left
    return bisect_left(nums, target)

def upper_bound(nums, target):
    from bisect import bisect_right
    return bisect_right(nums, target)

def selection_sort(nums):
    nums = nums[:]
    for i in range(len(nums)):
        j = min(range(i, len(nums)), key=nums.__getitem__)
        nums[i], nums[j] = nums[j], nums[i]
    return nums

def insertion_sort(nums):
    nums = nums[:]
    for i in range(1, len(nums)):
        x, j = nums[i], i
        while j and nums[j - 1] > x:
            nums[j] = nums[j - 1]
            j -= 1
        nums[j] = x
    return nums

def merge_sorted(a, b):
    i = j = 0
    out = []
    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            out.append(a[i]); i += 1
        else:
            out.append(b[j]); j += 1
    return out + a[i:] + b[j:]

def quickselect(nums, k):
    pivot = nums[len(nums) // 2]
    low = [x for x in nums if x < pivot]
    same = [x for x in nums if x == pivot]
    high = [x for x in nums if x > pivot]
    return quickselect(low, k) if k < len(low) else pivot if k < len(low) + len(same) else quickselect(high, k - len(low) - len(same))

def top_k(nums, k):
    from heapq import nlargest
    return nlargest(k, nums)

def kth_largest(nums, k):
    from heapq import nlargest
    return nlargest(k, nums)[-1]

def sort_by_frequency(items):
    from collections import Counter
    counts = Counter(items)
    return sorted(items, key=lambda x: (-counts[x], x))

def search_rotated(nums, target):
    lo, hi = 0, len(nums) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if nums[mid] == target:
            return mid
        if nums[lo] <= nums[mid]:
            if nums[lo] <= target < nums[mid]: hi = mid - 1
            else: lo = mid + 1
        elif nums[mid] < target <= nums[hi]: lo = mid + 1
        else: hi = mid - 1
    return -1

def merge_intervals(intervals):
    out = []
    for start, end in sorted(intervals):
        if out and start <= out[-1][1]:
            out[-1][1] = max(out[-1][1], end)
        else:
            out.append([start, end])
    return out

def rank_values(nums):
    rank = {x: i for i, x in enumerate(sorted(set(nums)))}
    return [rank[x] for x in nums]

def bucket_by_key(items, key):
    out = {}
    for item in items:
        out.setdefault(key(item), []).append(item)
    return out

def duplicates(items):
    from collections import Counter
    counts = Counter(items)
    return list(dict.fromkeys(x for x in items if counts[x] > 1))

def symmetric_difference_all(groups):
    from functools import reduce
    return reduce(set.symmetric_difference, map(set, groups), set())

def invert_multimap(mapping):
    out = {}
    for k, v in mapping.items():
        out.setdefault(v, []).append(k)
    return out

def merge_counts(a, b):
    from collections import Counter
    return dict(Counter(a) + Counter(b))

def group_anagrams(words):
    groups = {}
    for word in words:
        groups.setdefault(''.join(sorted(word)), []).append(word)
    return list(groups.values())

def most_common(items, k):
    from collections import Counter
    return [x for x, _ in Counter(items).most_common(k)]

def missing_numbers(nums, start, end):
    s = set(nums)
    return [x for x in range(start, end + 1) if x not in s]

def first_repeated(items):
    seen = set()
    return next((x for x in items if x in seen or seen.add(x)), None)

def pair_sum_exists(nums, target):
    seen = set()
    for x in nums:
        if target - x in seen:
            return True
        seen.add(x)
    return False

def two_sum_indices(nums, target):
    seen = {}
    for i, x in enumerate(nums):
        if target - x in seen:
            return [seen[target - x], i]
        seen[x] = i
    return []

def zero_sum_triplets(nums):
    nums = sorted(nums)
    return sorted({(a, b, -a - b) for i, a in enumerate(nums) for b in nums[i + 1:] if -a - b >= b and -a - b in nums})

def counter_difference(a, b):
    from collections import Counter
    return list((Counter(a) - Counter(b)).elements())

def equal_frequencies(items):
    from collections import Counter
    return len(set(Counter(items).values())) <= 1

def jaccard_similarity(a, b):
    a, b = set(a), set(b)
    return len(a & b) / len(a | b) if a | b else 1

def multiset_equal(a, b):
    from collections import Counter
    return Counter(a) == Counter(b)

def power_set(items):
    from itertools import combinations
    return [list(c) for r in range(len(items) + 1) for c in combinations(items, r)]

def permutations_of(items):
    from itertools import permutations
    return list(permutations(items))

def combinations_of(items, k):
    from itertools import combinations
    return list(combinations(items, k))

def subsets_sum(nums, target):
    from itertools import combinations
    return [list(c) for r in range(len(nums) + 1) for c in combinations(nums, r) if sum(c) == target]

def generate_parentheses(n):
    out = []
    def dfs(s, left, right):
        if len(s) == 2 * n: out.append(s)
        if left < n: dfs(s + '(', left + 1, right)
        if right < left: dfs(s + ')', left, right + 1)
    dfs('', 0, 0)
    return out

def n_queens_count(n):
    def dfs(cols, diag1, diag2):
        row = len(cols)
        if row == n: return 1
        return sum(dfs(cols | {c}, diag1 | {row-c}, diag2 | {row+c}) for c in range(n) if c not in cols and row-c not in diag1 and row+c not in diag2)
    return dfs(set(), set(), set())

def phone_combinations(digits):
    from itertools import product
    keys = {'2':'abc','3':'def','4':'ghi','5':'jkl','6':'mno','7':'pqrs','8':'tuv','9':'wxyz'}
    return [''.join(p) for p in product(*(keys[d] for d in digits))] if digits else []

def josephus(n, k):
    survivor = 0
    for size in range(2, n + 1):
        survivor = (survivor + k) % size
    return survivor

def hanoi_moves(n, source, target, spare):
    if not n:
        return []
    return hanoi_moves(n - 1, source, spare, target) + [(source, target)] + hanoi_moves(n - 1, spare, target, source)

def count_paths_grid(rows, cols):
    from math import comb
    return comb(rows + cols - 2, rows - 1)

def pascal_row(n):
    from math import comb
    return [comb(n, k) for k in range(n + 1)]

def catalan_number(n):
    from math import comb
    return comb(2 * n, n) // (n + 1)

def derangements(n):
    a, b = 1, 0
    for k in range(2, n + 1):
        a, b = b, (k - 1) * (a + b)
    return 1 if n == 0 else b

def integer_partitions(n):
    dp = [1] + [0] * n
    for x in range(1, n + 1):
        for s in range(x, n + 1):
            dp[s] += dp[s - x]
    return dp[n]

def coin_change_ways(coins, amount):
    dp = [1] + [0] * amount
    for coin in coins:
        for x in range(coin, amount + 1):
            dp[x] += dp[x - coin]
    return dp[amount]

def compositions(n, parts):
    from math import comb
    return comb(n - 1, parts - 1) if n >= parts > 0 else int(n == parts == 0)

def cartesian_product(groups):
    from itertools import product
    return list(product(*groups))

def choose_with_replacement(items, k):
    from itertools import combinations_with_replacement
    return list(combinations_with_replacement(items, k))

def max_subarray_sum(nums):
    best = current = nums[0]
    for x in nums[1:]:
        current = max(x, current + x)
        best = max(best, current)
    return best

def longest_increasing_subsequence(nums):
    from bisect import bisect_left
    tails = []
    for x in nums:
        i = bisect_left(tails, x)
        if i == len(tails): tails.append(x)
        else: tails[i] = x
    return len(tails)

def edit_distance(a, b):
    prev = list(range(len(b) + 1))
    for i, x in enumerate(a, 1):
        curr = [i] + [0] * len(b)
        for j, y in enumerate(b, 1):
            curr[j] = min(curr[j - 1] + 1, prev[j] + 1, prev[j - 1] + (x != y))
        prev = curr
    return prev[-1]

def longest_common_subsequence(a, b):
    dp = [0] * (len(b) + 1)
    for x in a:
        prev = 0
        for j, y in enumerate(b, 1):
            old = dp[j]
            dp[j] = prev + 1 if x == y else max(dp[j], dp[j - 1])
            prev = old
    return dp[-1]

def knapsack(weights, values, capacity):
    dp = [0] * (capacity + 1)
    for w, v in zip(weights, values):
        for c in range(capacity, w - 1, -1):
            dp[c] = max(dp[c], dp[c - w] + v)
    return dp[capacity]

def minimum_coins(coins, amount):
    dp = [0] + [amount + 1] * amount
    for x in range(1, amount + 1):
        dp[x] = min((dp[x - c] + 1 for c in coins if c <= x), default=amount + 1)
    return dp[amount] if dp[amount] <= amount else -1

def house_robber(nums):
    prev = curr = 0
    for x in nums:
        prev, curr = curr, max(curr, prev + x)
    return curr

def climb_stairs(n):
    a, b = 1, 1
    for _ in range(n):
        a, b = b, a + b
    return a

def can_partition_equal(nums):
    total = sum(nums)
    if total % 2: return False
    target, sums = total // 2, {0}
    for x in nums: sums |= {s + x for s in sums if s + x <= target}
    return target in sums

def word_break(text, words):
    words = set(words)
    dp = [True] + [False] * len(text)
    for i in range(1, len(text) + 1):
        dp[i] = any(dp[j] and text[j:i] in words for j in range(i))
    return dp[-1]

def min_path_sum(grid):
    dp = [float('inf')] * len(grid[0])
    dp[0] = 0
    for row in grid:
        for j, x in enumerate(row):
            dp[j] = min(dp[j], dp[j - 1] if j else float('inf')) + x
    return dp[-1]

def unique_paths_with_obstacles(grid):
    dp = [1] + [0] * (len(grid[0]) - 1)
    for row in grid:
        for j, blocked in enumerate(row):
            dp[j] = 0 if blocked else dp[j] + (dp[j - 1] if j else 0)
    return dp[-1]

def longest_palindromic_subsequence(text):
    rev = text[::-1]
    dp = [0] * (len(text) + 1)
    for x in text:
        prev = 0
        for j, y in enumerate(rev, 1):
            old = dp[j]
            dp[j] = prev + 1 if x == y else max(dp[j], dp[j - 1])
            prev = old
    return dp[-1]

def matrix_chain_cost(dimensions):
    n = len(dimensions) - 1
    dp = [[0] * n for _ in range(n)]
    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            dp[i][j] = min(dp[i][k] + dp[k + 1][j] + dimensions[i] * dimensions[k + 1] * dimensions[j + 1] for k in range(i, j))
    return dp[0][-1] if n else 0

def rod_cut(prices, length):
    dp = [0] * (length + 1)
    for n in range(1, length + 1):
        dp[n] = max(prices[k - 1] + dp[n - k] for k in range(1, min(n, len(prices)) + 1))
    return dp[length]

def decode_ways(digits):
    if not digits or digits[0] == '0': return 0
    a = b = 1
    for i in range(1, len(digits)):
        a, b = b, (b if digits[i] != '0' else 0) + (a if 10 <= int(digits[i-1:i+1]) <= 26 else 0)
    return b

def maximum_product_subarray(nums):
    hi = lo = best = nums[0]
    for x in nums[1:]:
        hi, lo = max(x, x * hi, x * lo), min(x, x * hi, x * lo)
        best = max(best, hi)
    return best

def minimum_triangle_path(triangle):
    dp = triangle[-1][:]
    for row in triangle[-2::-1]:
        dp = [x + min(dp[i], dp[i + 1]) for i, x in enumerate(row)]
    return dp[0]

def stock_profit_one(prices):
    best, low = 0, float('inf')
    for price in prices:
        low = min(low, price)
        best = max(best, price - low)
    return best

def activity_selection(intervals):
    chosen, end = [], float('-inf')
    for interval in sorted(intervals, key=lambda x: x[1]):
        if interval[0] >= end:
            chosen.append(interval)
            end = interval[1]
    return chosen

def min_arrows(intervals):
    arrows, end = 0, float('-inf')
    for start, finish in sorted(intervals, key=lambda x: x[1]):
        if start > end:
            arrows += 1; end = finish
    return arrows

def minimize_number_after_deletions(digits, k):
    stack = []
    for d in digits:
        while k and stack and stack[-1] > d:
            stack.pop(); k -= 1
        stack.append(d)
    return ''.join(stack[:-k] if k else stack).lstrip('0') or '0'

def can_reach_end(nums):
    far = 0
    for i, jump in enumerate(nums):
        if i > far: return False
        far = max(far, i + jump)
    return True

def minimum_jumps(nums):
    jumps = end = far = 0
    for i, step in enumerate(nums[:-1]):
        far = max(far, i + step)
        if i == end:
            jumps += 1; end = far
    return jumps

def assign_cookies(greed, cookies):
    greed, cookies = sorted(greed), sorted(cookies)
    i = 0
    for cookie in cookies:
        i += i < len(greed) and cookie >= greed[i]
    return i

def partition_labels(text):
    last = {c: i for i, c in enumerate(text)}
    out, start = [], 0
    end = 0
    for i, c in enumerate(text):
        end = max(end, last[c])
        if i == end:
            out.append(end - start + 1); start = i + 1
    return out

def reconstruct_queue(people):
    queue = []
    for person in sorted(people, key=lambda x: (-x[0], x[1])):
        queue.insert(person[1], person)
    return queue

def erase_overlap_intervals(intervals):
    end, kept = float('-inf'), 0
    for start, finish in sorted(intervals, key=lambda x: x[1]):
        if start >= end:
            kept += 1; end = finish
    return len(intervals) - kept

def maximum_units(box_types, truck_size):
    total = 0
    for boxes, units in sorted(box_types, key=lambda x: -x[1]):
        take = min(boxes, truck_size)
        total += take * units; truck_size -= take
    return total

def minimum_rooms(intervals):
    import heapq
    rooms = []
    for start, end in sorted(intervals):
        if rooms and rooms[0] <= start: heapq.heapreplace(rooms, end)
        else: heapq.heappush(rooms, end)
    return len(rooms)

def schedule_tasks(tasks, cooldown):
    from collections import Counter
    counts = Counter(tasks).values()
    top = max(counts, default=0)
    ties = sum(c == top for c in counts)
    return max(len(tasks), (top - 1) * (cooldown + 1) + ties)

def max_pair_chain(pairs):
    end, count = float('-inf'), 0
    for a, b in sorted(pairs, key=lambda x: x[1]):
        if a > end: count, end = count + 1, b
    return count

def count_leaves(root):
    if not root: return 0
    return 1 if not root.left and not root.right else count_leaves(root.left) + count_leaves(root.right)

def invert_tree(root):
    if root:
        root.left, root.right = invert_tree(root.right), invert_tree(root.left)
    return root

def is_symmetric(root):
    def mirror(a, b):
        return a is b if not a or not b else a.val == b.val and mirror(a.left, b.right) and mirror(a.right, b.left)
    return not root or mirror(root.left, root.right)

def bst_search(root, target):
    while root and root.val != target:
        root = root.left if target < root.val else root.right
    return root

def bst_min(root):
    while root.left: root = root.left
    return root.val

def bst_max(root):
    while root.right: root = root.right
    return root.val

def is_valid_bst(root):
    def check(node, lo, hi):
        return not node or lo < node.val < hi and check(node.left, lo, node.val) and check(node.right, node.val, hi)
    return check(root, float('-inf'), float('inf'))

def lowest_common_ancestor_bst(root, a, b):
    while root:
        if b < root.val: root = root.left
        elif a > root.val: root = root.right
        else: return root

def has_path_sum(root, target):
    if not root: return False
    if not root.left and not root.right: return root.val == target
    return has_path_sum(root.left, target - root.val) or has_path_sum(root.right, target - root.val)

def tree_diameter(root):
    best = 0
    def height(node):
        nonlocal best
        if not node: return 0
        left, right = height(node.left), height(node.right)
        best = max(best, left + right)
        return 1 + max(left, right)
    height(root)
    return best

def is_balanced_tree(root):
    def height(node):
        if not node: return 0
        a, b = height(node.left), height(node.right)
        return -1 if a < 0 or b < 0 or abs(a - b) > 1 else 1 + max(a, b)
    return height(root) >= 0

def sum_left_leaves(root):
    if not root: return 0
    left = root.left.val if root.left and not root.left.left and not root.left.right else sum_left_leaves(root.left)
    return left + sum_left_leaves(root.right)

def bfs_order(graph, start):
    from collections import deque
    seen, queue, out = {start}, deque([start]), []
    while queue:
        node = queue.popleft(); out.append(node)
        for nxt in graph.get(node, []):
            if nxt not in seen: seen.add(nxt); queue.append(nxt)
    return out

def dfs_order(graph, start):
    out, seen = [], set()
    def dfs(node):
        if node in seen: return
        seen.add(node); out.append(node)
        for nxt in graph.get(node, []): dfs(nxt)
    dfs(start)
    return out

def has_path(graph, start, target):
    stack, seen = [start], set()
    while stack:
        node = stack.pop()
        if node == target:
            return True
        if node not in seen:
            seen.add(node)
            stack.extend(graph.get(node, []))
    return False

def shortest_unweighted_path(graph, start, target):
    from collections import deque
    queue = deque([[start]]); seen = {start}
    while queue:
        path = queue.popleft(); node = path[-1]
        if node == target: return path
        for nxt in graph.get(node, []):
            if nxt not in seen: seen.add(nxt); queue.append(path + [nxt])
    return []

def connected_components(graph):
    unseen, out = set(graph), []
    while unseen:
        stack = [unseen.pop()]; comp = set(stack)
        while stack:
            for nxt in graph.get(stack.pop(), []):
                if nxt in unseen: unseen.remove(nxt); comp.add(nxt); stack.append(nxt)
        out.append(comp)
    return out

def is_bipartite(graph):
    color = {}
    for start in graph:
        if start in color: continue
        color[start] = 0; stack = [start]
        while stack:
            node = stack.pop()
            for nxt in graph[node]:
                if nxt in color and color[nxt] == color[node]: return False
                if nxt not in color: color[nxt] = color[node] ^ 1; stack.append(nxt)
    return True

def topological_sort(graph):
    from collections import Counter, deque
    indegree = Counter(v for edges in graph.values() for v in edges)
    queue = deque(node for node in graph if not indegree[node]); out = []
    while queue:
        node = queue.popleft(); out.append(node)
        for nxt in graph[node]:
            indegree[nxt] -= 1
            if not indegree[nxt]: queue.append(nxt)
    return out

def has_directed_cycle(graph):
    visiting, done = set(), set()
    def dfs(node):
        if node in visiting: return True
        if node in done: return False
        visiting.add(node)
        cycle = any(dfs(nxt) for nxt in graph.get(node, []))
        visiting.remove(node); done.add(node)
        return cycle
    return any(dfs(node) for node in graph)

def dijkstra(graph, start):
    import heapq
    dist, heap = {start: 0}, [(0, start)]
    while heap:
        d, node = heapq.heappop(heap)
        if d != dist[node]: continue
        for nxt, w in graph.get(node, []):
            nd = d + w
            if nd < dist.get(nxt, float('inf')):
                dist[nxt] = nd; heapq.heappush(heap, (nd, nxt))
    return dist

def bellman_ford(n, edges, source):
    dist = [float('inf')] * n; dist[source] = 0
    for _ in range(n - 1):
        changed = False
        for a, b, w in edges:
            if dist[a] + w < dist[b]: dist[b], changed = dist[a] + w, True
        if not changed: break
    return dist

def floyd_warshall(matrix):
    dist = [row[:] for row in matrix]
    for k in range(len(dist)):
        for i in range(len(dist)):
            for j in range(len(dist)):
                dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
    return dist

def minimum_spanning_tree_cost(n, edges):
    parent = list(range(n))
    def find(x):
        while x != parent[x]:
            parent[x] = parent[parent[x]]; x = parent[x]
        return x
    cost = 0
    for w, a, b in sorted(edges):
        ra, rb = find(a), find(b)
        if ra != rb: parent[ra] = rb; cost += w
    return cost

def count_islands(grid):
    grid = [list(row) for row in grid]; count = 0
    for i in range(len(grid)):
        for j in range(len(grid[0])):
            if not grid[i][j]: continue
            count += 1; stack = [(i, j)]; grid[i][j] = 0
            while stack:
                x, y = stack.pop()
                for a, b in ((x-1,y),(x+1,y),(x,y-1),(x,y+1)):
                    if 0 <= a < len(grid) and 0 <= b < len(grid[0]) and grid[a][b]: grid[a][b] = 0; stack.append((a,b))
    return count

def rotting_time(grid):
    from collections import deque
    q = deque((i, j, 0) for i, row in enumerate(grid) for j, x in enumerate(row) if x == 2); last = 0
    while q:
        i, j, last = q.popleft()
        for a, b in ((i-1,j),(i+1,j),(i,j-1),(i,j+1)):
            if 0 <= a < len(grid) and 0 <= b < len(grid[0]) and grid[a][b] == 1:
                grid[a][b] = 2; q.append((a, b, last + 1))
    return -1 if any(1 in row for row in grid) else last

def word_ladder_length(begin, end, words):
    from collections import deque
    words = set(words); q = deque([(begin, 1)])
    while q:
        word, d = q.popleft()
        if word == end: return d
        for i in range(len(word)):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                nxt = word[:i] + c + word[i+1:]
                if nxt in words: words.remove(nxt); q.append((nxt, d + 1))
    return 0

def network_delay_time(edges, n, source):
    import heapq
    graph = {i: [] for i in range(1, n + 1)}
    for a, b, w in edges:
        graph[a].append((b, w))
    dist, heap = {source: 0}, [(0, source)]
    while heap:
        d, node = heapq.heappop(heap)
        if d != dist[node]:
            continue
        for nxt, w in graph[node]:
            nd = d + w
            if nd < dist.get(nxt, float('inf')):
                dist[nxt] = nd
                heapq.heappush(heap, (nd, nxt))
    return max(dist.values()) if len(dist) == n else -1

def euclidean_distance(a, b):
    from math import dist
    return dist(a, b)

def bounding_box(points):
    xs, ys = zip(*points)
    return min(xs), min(ys), max(xs), max(ys)

def matrix_multiply(a, b):
    bt = list(zip(*b))
    return [[sum(x * y for x, y in zip(row, col)) for col in bt] for row in a]

def extract_integers(text):
    import re
    return list(map(int, re.findall(r'-?\d+', text)))

def extract_words(text):
    import re
    return re.findall(r'\b\w+\b', text)

def word_frequencies(text):
    import re
    from collections import Counter
    return dict(Counter(re.findall(r'\w+', text.lower())))

def sentence_count(text):
    import re
    return len([x for x in re.split(r'[.!?]+', text) if x.strip()])

def parse_ranges(text):
    out = []
    for part in text.split(','):
        if '-' in part:
            a, b = map(int, part.split('-')); out.extend(range(a, b + 1))
        else: out.append(int(part))
    return out

def common_words(a, b):
    import re
    words = lambda s: set(re.findall(r'\w+', s.lower()))
    return sorted(words(a) & words(b))

def replace_many(text, replacements):
    for old, new in replacements.items(): text = text.replace(old, new)
    return text

def slugify(text):
    import re
    return re.sub(r'-+', '-', re.sub(r'[^a-z0-9]+', '-', text.lower())).strip('-')

def days_between(a, b):
    from datetime import date
    return abs((date.fromisoformat(a) - date.fromisoformat(b)).days)

def days_in_month(year, month):
    from calendar import monthrange
    return monthrange(year, month)[1]

def weekday_name(date_string):
    from datetime import date
    return date.fromisoformat(date_string).strftime('%A')

def add_days(date_string, days):
    from datetime import date, timedelta
    return (date.fromisoformat(date_string) + timedelta(days=days)).isoformat()

def z_scores(nums):
    from math import sqrt
    mean = sum(nums) / len(nums)
    sd = sqrt(sum((x - mean) ** 2 for x in nums) / len(nums))
    return [(x - mean) / sd for x in nums] if sd else [0] * len(nums)

def variance(nums):
    mean = sum(nums) / len(nums)
    return sum((x - mean) ** 2 for x in nums) / len(nums)

def moving_average(nums, size):
    sums = [0]
    for x in nums: sums.append(sums[-1] + x)
    return [(sums[i + size] - sums[i]) / size for i in range(len(nums) - size + 1)]

def pearson_correlation(a, b):
    from math import sqrt
    ma, mb = sum(a) / len(a), sum(b) / len(b)
    da, db = [x - ma for x in a], [y - mb for y in b]
    return sum(x * y for x, y in zip(da, db)) / sqrt(sum(x*x for x in da) * sum(y*y for y in db))

def min_max_scale(nums):
    lo, hi = min(nums), max(nums)
    return [(x - lo) / (hi - lo) for x in nums] if hi > lo else [0] * len(nums)

def cumulative_max(nums):
    from itertools import accumulate
    return list(accumulate(nums, max))

def cumulative_min(nums):
    from itertools import accumulate
    return list(accumulate(nums, min))

def normalize_probabilities(weights):
    total = sum(weights)
    return [w / total for w in weights]

def entropy(probabilities):
    from math import log2
    return -sum(p * log2(p) for p in probabilities if p)

def root_mean_square(nums):
    from math import sqrt
    return sqrt(sum(x * x for x in nums) / len(nums))

def xor_all(nums):
    from functools import reduce
    from operator import xor
    return reduce(xor, nums, 0)

def single_number(nums):
    from functools import reduce
    from operator import xor
    return reduce(xor, nums, 0)

def sieve_primes(n):
    sieve = [True] * (n + 1)
    if n >= 0: sieve[0] = False
    if n >= 1: sieve[1] = False
    for p in range(2, int(n ** .5) + 1):
        if sieve[p]: sieve[p*p:n+1:p] = [False] * (((n - p*p) // p) + 1)
    return [i for i, prime in enumerate(sieve) if prime]

def prime_factors(n):
    out, d = [], 2
    while d * d <= n:
        while n % d == 0: out.append(d); n //= d
        d += 1
    return out + ([n] if n > 1 else [])

def totient(n):
    result, p = n, 2
    while p * p <= n:
        if n % p == 0:
            while n % p == 0:
                n //= p
            result -= result // p
        p += 1
    return result - result // n if n > 1 else result

def modular_power(base, exponent, modulus):
    result = 1
    while exponent:
        if exponent & 1: result = result * base % modulus
        base = base * base % modulus; exponent >>= 1
    return result % modulus

def mod_inverse(a, modulus):
    def egcd(x, y):
        if not y:
            return x, 1, 0
        g, p, q = egcd(y, x % y)
        return g, q, p - x // y * q
    g, x, _ = egcd(a, modulus)
    if g != 1:
        raise ValueError('inverse does not exist')
    return x % modulus

def chinese_remainder_pair(r1, m1, r2, m2):
    def inverse(a, m):
        return pow(a, -1, m)
    return (r1 + (r2 - r1) * inverse(m1, m2) % m2 * m1) % (m1 * m2)

def is_coprime(a, b):
    from math import gcd
    return gcd(a, b) == 1

def is_happy_number(n):
    seen = set()
    while n != 1 and n not in seen:
        seen.add(n); n = sum(int(d) ** 2 for d in str(n))
    return n == 1

def evaluate_rpn(tokens):
    stack = []
    for token in tokens:
        if token in '+-*/':
            b, a = stack.pop(), stack.pop()
            stack.append({'+': a+b, '-': a-b, '*': a*b, '/': int(a/b)}[token])
        else: stack.append(int(token))
    return stack[-1]

def valid_brackets(text):
    pairs, stack = {')':'(', ']':'[', '}':'{'}, []
    for c in text:
        if c in '([{': stack.append(c)
        elif c in pairs and (not stack or stack.pop() != pairs[c]): return False
    return not stack

def next_greater_elements(nums):
    out, stack = [-1] * len(nums), []
    for i, x in enumerate(nums):
        while stack and nums[stack[-1]] < x: out[stack.pop()] = x
        stack.append(i)
    return out

def daily_warmer_days(temperatures):
    out, stack = [0] * len(temperatures), []
    for i, t in enumerate(temperatures):
        while stack and temperatures[stack[-1]] < t:
            j = stack.pop(); out[j] = i - j
        stack.append(i)
    return out

def largest_histogram_rectangle(heights):
    stack, best = [], 0
    for i, h in enumerate(heights + [0]):
        start = i
        while stack and stack[-1][1] > h:
            j, height = stack.pop(); best = max(best, height * (i - j)); start = j
        stack.append((start, h))
    return best

def min_stack_operations(values):
    out, current = [], float('inf')
    for x in values:
        current = min(current, x); out.append(current)
    return out

def queue_using_stacks(commands):
    incoming, outgoing, result = [], [], []
    for op, value in commands:
        if op == 'push': incoming.append(value)
        else:
            if not outgoing: outgoing = incoming[::-1]; incoming.clear()
            result.append(outgoing.pop())
    return result

def min_window_sum(nums, size):
    total = sum(nums[:size]); best = total
    for a, b in zip(nums, nums[size:]):
        total += b - a; best = min(best, total)
    return best

def longest_distinct_substring(text):
    last, start, best = {}, 0, 0
    for i, c in enumerate(text):
        start = max(start, last.get(c, -1) + 1); last[c] = i; best = max(best, i - start + 1)
    return best

def longest_ones_after_flips(bits, k):
    left = 0
    for right, bit in enumerate(bits):
        k -= not bit
        if k < 0: k += not bits[left]; left += 1
    return len(bits) - left

def subarray_sum_count(nums, target):
    from collections import Counter
    counts, total, answer = Counter({0: 1}), 0, 0
    for x in nums:
        total += x; answer += counts[total - target]; counts[total] += 1
    return answer

def circular_max_subarray_sum(nums):
    def kadane(values):
        best = current = values[0]
        for x in values[1:]:
            current = max(x, current + x)
            best = max(best, current)
        return best
    best = kadane(nums)
    return best if best < 0 else max(best, sum(nums) + kadane([-x for x in nums]))

def trap_rainwater(heights):
    left, right, low, high, water = 0, len(heights) - 1, 0, 0, 0
    while left <= right:
        if heights[left] <= heights[right]:
            low = max(low, heights[left]); water += low - heights[left]; left += 1
        else:
            high = max(high, heights[right]); water += high - heights[right]; right -= 1
    return water

def game_of_life_step(board):
    rows, cols = len(board), len(board[0])
    return [[int(sum(board[x][y] for x in range(max(0,i-1), min(rows,i+2)) for y in range(max(0,j-1), min(cols,j+2))) - board[i][j] in (3, 3 - board[i][j])) for j in range(cols)] for i in range(rows)]

def roman_to_integer(text):
    values = {'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000}
    return sum(-values[c] if i + 1 < len(text) and values[c] < values[text[i + 1]] else values[c] for i, c in enumerate(text))

def integer_to_roman(n):
    pairs = [(1000,'M'),(900,'CM'),(500,'D'),(400,'CD'),(100,'C'),(90,'XC'),(50,'L'),(40,'XL'),(10,'X'),(9,'IX'),(5,'V'),(4,'IV'),(1,'I')]
    out = ''
    for value, symbol in pairs:
        count, n = divmod(n, value); out += symbol * count
    return out

class FileManager:
    def __init__(self):
        self.file1 = None
        self.file2 = None
        self.file3 = None

    def open_resources(self):
