def max_sum(tri, n):
    if n > 1:
        tri[1][1] = tri[1][1] + tri[0][0]
        tri[1][0] = tri[1][0] + tri[0][0]
    for i in range(2, n):
        tri[i][0] = tri[i][0] + tri[i - 1][0]
        tri[i][i] = tri[i][i] + tri[i - 1][i - 1]
        for j in range(1, i):
            tri[i][j] = tri[i][j] + tri[i - 1][j - 1] if tri[i][j] + tri[i - 1][j - 1] >= tri[i][j] + tri[i - 1][j] else tri[i][j] + tri[i - 1][j]
    return max(tri[n - 1])

