def babylonian_squareroot(number):
    if number == 0:
        return 0
    g = number / 2.0
    g2 = g + 1
    while g != g2:
        n = number / g
        g2 = g
        g = (g + n) / 2
    return g

def lps(str):
    n = len(str)
    L = [[0 for x in range(n)] for x in range(n)]
    for i in range(n):
        L[i][i] = 1
    for cl in range(2, n + 1):
        for i in range(n - cl + 1):
            j = i + cl - 1
            L[i][j] = 2 if str[i] == str[j] and cl == 2 else L[i + 1][j - 1] + 2 if str[i] == str[j] else max(L[i][j - 1], L[i + 1][j])
    return L[0][n - 1]

