def max_sum_increasing_subseq(a, n, index, k):
    dp = [[0 for i in range(n)] for i in range(n)]
    for i in range(n):
        dp[0][i] = a[i] + a[0] if a[i] > a[0] else a[i]
    for i in range(1, n):
        for j in range(n):
            dp[i][j] = (dp[i - 1][i] + a[j] if dp[i - 1][i] + a[j] > dp[i - 1][j] else dp[i - 1][j]) if a[j] > a[i] and j > i else dp[i - 1][j]
    return dp[index][k]

def set_left_most_unset_bit(n):
    if not n & n + 1:
        return n
    pos, temp, count = 0, n, 0
    while temp:
        if not temp & 1:
            pos = count
        count += 1
        temp >>= 1
    return n | 1 << pos

