    for index in range(n):
        if out_of_place >= 0:
            if arr[index] >= 0 and arr[out_of_place] < 0 or (arr[index] < 0 and arr[out_of_place] >= 0):
                arr = right_rotate(arr, n, out_of_place, index)
                if index - out_of_place > 2:
                    out_of_place += 2
                else:
                    out_of_place = -1
        if out_of_place == -1:
