def find_median_sorted_arrays(nums1, nums2):
    if len(nums1) > len(nums2):
        nums1, nums2 = nums2, nums1
    m, n = len(nums1), len(nums2)
    lo, hi = 0, m
    half = (m + n + 1) // 2
    while lo <= hi:
        i = (lo + hi) // 2
        j = half - i
        if i < m and nums2[j-1] > nums1[i]:
            lo = i + 1
        elif i > 0 and nums1[i-1] > nums2[j]:
            hi = i - 1
        else:
            max_left = max(nums1[i-1] if i>0 else float('-inf'), nums2[j-1] if j>0 else float('-inf'))
            if (m+n)%2:
                return max_left
            min_right = min(nums1[i] if i<m else float('inf'), nums2[j] if j<n else float('inf'))
            return (max_left + min_right) / 2

def kth_largest(nums, k):
    import random
    def partition(l, r, pivot_idx):
        pivot = nums[pivot_idx]
        nums[pivot_idx], nums[r] = nums[r], nums[pivot_idx]
        store = l
        for i in range(l, r):
            if nums[i] < pivot:
                nums[store], nums[i] = nums[i], nums[store]
                store += 1
        nums[r], nums[store] = nums[store], nums[r]
        return store
    def select(l, r, k_smallest):
        if l == r:
            return nums[l]
        pivot_idx = random.randint(l, r)
        pivot_idx = partition(l, r, pivot_idx)
        if k_smallest == pivot_idx:
            return nums[k_smallest]
        elif k_smallest < pivot_idx:
            return select(l, pivot_idx-1, k_smallest)
        else:
            return select(pivot_idx+1, r, k_smallest)
    return select(0, len(nums)-1, len(nums)-k)

