def preorder_iterative(root):
    if not root:
        return []
    res, stack = [], [root]
    while stack:
        node = stack.pop()
        res.append(node.val)
        if node.right:
            stack.append(node.right)
        if node.left:
            stack.append(node.left)
    return res

def postorder_iterative(root):
    if not root:
        return []
    res, stack = [], [root]
    while stack:
        node = stack.pop()
        res.append(node.val)
        if node.left:
            stack.append(node.left)
        if node.right:
            stack.append(node.right)
    return res[::-1]

class MedianFinder:
    def __init__(self):
        from heapq import heappush, heappop
        self.maxh = []
        self.minh = []
    def addNum(self, num):
        heappush(self.maxh, -num)
        heappush(self.minh, -heappop(self.maxh))
        if len(self.minh) > len(self.maxh):
            heappush(self.maxh, -heappop(self.minh))
    def findMedian(self):
        if len(self.maxh) > len(self.minh):
            return -self.maxh[0]
        return (-self.maxh[0] + self.minh[0]) / 2

