def search_range(nums, target):
    def binary_left():
        l, r = 0, len(nums)-1
        while l <= r:
            mid = (l+r)//2
            if nums[mid] < target:
                l = mid+1
            else:
                r = mid-1
        return l
    left = binary_left()
    if left == len(nums) or nums[left] != target:
        return [-1, -1]
    def binary_right():
        l, r = 0, len(nums)-1
        while l <= r:
            mid = (l+r)//2
            if nums[mid] <= target:
                l = mid+1
            else:
                r = mid-1
        return r
    return [left, binary_right()]

def min_cost_climbing_stairs(cost):
    a = b = 0
    for x in reversed(cost):
        a, b = x + min(a, b), a
    return min(a, b)

def rob_ii(nums):
    def rob_range(nums):
        prev = cur = 0
        for x in nums:
            prev, cur = cur, max(cur, prev + x)
        return cur
    if len(nums) == 1:
        return nums[0]
    return max(rob_range(nums[:-1]), rob_range(nums[1:]))

def rob_iii(root):
    def helper(node):
        if not node:
            return (0, 0)
        l_rob, l_not = helper(node.left)
        r_rob, r_not = helper(node.right)
        rob = node.val + l_not + r_not
        not_rob = max(l_rob, l_not) + max(r_rob, r_not)
        return (rob, not_rob)
    return max(helper(root))

def can_jump(nums):
    max_reach = 0
    for i, n in enumerate(nums):
        if i > max_reach:
            return False
        max_reach = max(max_reach, i + n)
    return True

def jump_game_ii(nums):
    jumps = cur_end = cur_farthest = 0
    for i in range(len(nums)-1):
        cur_farthest = max(cur_farthest, i + nums[i])
        if i == cur_end:
            jumps += 1
            cur_end = cur_farthest
    return jumps

def length_of_lis(nums):
    tails = []
    for x in nums:
        i = 0
        j = len(tails)
        while i < j:
            m = (i+j)//2
            if tails[m] < x:
                i = m+1
            else:
                j = m
        if i == len(tails):
            tails.append(x)
        else:
            tails[i] = x
    return len(tails)

def find_length_repeated(A, B):
    m, n = len(A), len(B)
    dp = [0] * (n+1)
    max_len = 0
    for i in range(1, m+1):
        prev = 0
        for j in range(1, n+1):
            temp = dp[j]
            if A[i-1] == B[j-1]:
                dp[j] = prev + 1
                max_len = max(max_len, dp[j])
            else:
                dp[j] = 0
            prev = temp
    return max_len

def coin_change_ii(amount, coins):
    dp = [0] * (amount+1)
    dp[0] = 1
    for coin in coins:
        for i in range(coin, amount+1):
            dp[i] += dp[i-coin]
    return dp[amount]

def num_squares(n):
    while n % 4 == 0:
        n //= 4
    if n % 8 == 7:
        return 4
    a = 0
    while a * a <= n:
        b = int((n - a * a)**0.5)
        if a * a + b * b == n:
            return (a > 0) + (b > 0)
        a += 1
    return 3

def integer_break(n):
    if n <= 3:
        return n - 1
    quotient, remainder = divmod(n, 3)
    if remainder == 0:
        return 3 ** quotient
    elif remainder == 1:
        return 3 ** (quotient - 1) * 4
    return 3 ** quotient * 2

def climb_stairs_ways(n):
