    dp = [0] * n
    dp[0] = 1
    for i in range(m):
        for j in range(n):
            if obstableGrid[i][j] == 1:
                dp[j] = 0
            elif j > 0:
                dp[j] += dp[j-1]
    return dp[-1]

def maximal_square(matrix):
    if not matrix:
        return 0
    m, n = len(matrix), len(matrix[0])
    dp = [0] * (n+1)
    max_side = prev = 0
    for i in range(1, m+1):
        for j in range(1, n+1):
            temp = dp[j]
            if matrix[i-1][j-1] == '1':
                dp[j] = min(dp[j-1], dp[j], prev) + 1
                max_side = max(max_side, dp[j])
            else:
                dp[j] = 0
            prev = temp
    return max_side * max_side

def longest_valid_parentheses_len(s):
    dp = [0] * (len(s)+1)
    maxlen = 0
    for i in range(1, len(s)):
        if s[i] == ')':
            if s[i-1] == '(':
                dp[i+1] = dp[i-1] + 2
            elif i - dp[i] - 1 >= 0 and s[i - dp[i] - 1] == '(':
                dp[i+1] = dp[i] + 2 + dp[i - dp[i] - 1]
            maxlen = max(maxlen, dp[i+1])
    return maxlen

def count_substrings(s):
    cnt = 0
    for i in range(len(s)):
        l = r = i
        while l >= 0 and r < len(s) and s[l] == s[r]:
            cnt += 1; l -= 1; r += 1
        l, r = i, i+1
        while l >= 0 and r < len(s) and s[l] == s[r]:
            cnt += 1; l -= 1; r += 1
    return cnt

def longest_palindrome_subseq(s):
    n = len(s)
    dp = [1] * n
    for i in range(n-1, -1, -1):
        prev = 0
        for j in range(i+1, n):
            temp = dp[j]
            if s[i] == s[j]:
                dp[j] = prev + 2
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = temp
    return dp[-1] if n else 0

def partition_labels(s):
    last = {c: i for i, c in enumerate(s)}
    start = end = 0
    res = []
    for i, c in enumerate(s):
        end = max(end, last[c])
        if i == end:
            res.append(end - start + 1)
            start = end + 1
    return res

