        return 0
    s = 0
    if root.left and not root.left.left and not root.left.right:
        s += root.left.val
    return s + sum_of_left_leaves(root.left) + sum_of_left_leaves(root.right)

def merge_trees(t1, t2):
    if not t1:
        return t2
    if not t2:
        return t1
    t1.val += t2.val
    t1.left = merge_trees(t1.left, t2.left)
    t1.right = merge_trees(t1.right, t2.right)
    return t1

def zigzag_level_order(root):
    if not root:
        return []
    res, queue, reverse = [], [root], False
    while queue:
        level = [node.val for node in queue]
        if reverse:
            level.reverse()
        res.append(level)
        reverse = not reverse
        next_level = []
        for node in queue:
            if node.left:
                next_level.append(node.left)
            if node.right:
                next_level.append(node.right)
        queue = next_level
    return res

def connect(root):
    if not root:
        return None
    cur = root
    while cur.left:
        nxt = cur.left
        while cur:
            cur.left.next = cur.right
            if cur.next:
                cur.right.next = cur.next.left
            cur = cur.next
        cur = nxt
    return root

def flatten(root):
    cur = root
    while cur:
        if cur.left:
            predecessor = cur.left
            while predecessor.right:
                predecessor = predecessor.right
            predecessor.right = cur.right
            cur.right = cur.left
            cur.left = None
        cur = cur.right

class BSTIterator:
    def __init__(self, root):
        self.stack = []
        self._leftmost_inorder(root)
    def _leftmost_inorder(self, node):
        while node:
            self.stack.append(node)
            node = node.left
    def next(self):
        top = self.stack.pop()
        if top.right:
            self._leftmost_inorder(top.right)
        return top.val
    def hasNext(self):
        return len(self.stack) > 0

def lowest_common_ancestor(root, p, q):
    if not root or root == p or root == q:
        return root
    left = lowest_common_ancestor(root.left, p, q)
    right = lowest_common_ancestor(root.right, p, q)
    if left and right:
        return root
    return left or right

def delete_bst_node(root, key):
    if not root:
        return None
    if key < root.val:
        root.left = delete_bst_node(root.left, key)
    elif key > root.val:
        root.right = delete_bst_node(root.right, key)
    else:
        if not root.left:
            return root.right
        if not root.right:
            return root.left
        min_node = root.right
        while min_node.left:
            min_node = min_node.left
        root.val = min_node.val
        root.right = delete_bst_node(root.right, min_node.val)
    return root

def trim_bst(root, low, high):
    if not root:
        return None
    if root.val < low:
        return trim_bst(root.right, low, high)
    if root.val > high:
        return trim_bst(root.left, low, high)
    root.left = trim_bst(root.left, low, high)
    root.right = trim_bst(root.right, low, high)
    return root

def get_minimum_difference(root):
    prev, ans = None, float('inf')
    def inorder(node):
        nonlocal prev, ans
        if not node:
            return
        inorder(node.left)
        if prev is not None:
            ans = min(ans, node.val - prev)
        prev = node.val
        inorder(node.right)
    inorder(root)
    return ans

