def reorganize_string(s):
    from collections import Counter
    import heapq
    cnt = Counter(s)
    heap = [(-v, k) for k, v in cnt.items()]
    heapq.heapify(heap)
    res = []
    while len(heap) > 1:
        neg_v1, c1 = heapq.heappop(heap)
        neg_v2, c2 = heapq.heappop(heap)
        res.extend([c1, c2])
        if neg_v1 + 1 < 0:
            heapq.heappush(heap, (neg_v1+1, c1))
        if neg_v2 + 1 < 0:
            heapq.heappush(heap, (neg_v2+1, c2))
    if heap:
        neg_v, c = heap[0]
        if -neg_v > 1:
            return ''
        res.append(c)
    return ''.join(res)

from collections import defaultdict, OrderedDict
class LFUCache:
    def __init__(self, capacity):
        self.cap = capacity
        self.min_freq = 0
        self.key_val = {}
        self.key_freq = {}
        self.freq_keys = defaultdict(OrderedDict)
    def get(self, key):
        if key not in self.key_val:
            return -1
        self._increase_freq(key)
        return self.key_val[key]
    def put(self, key, value):
        if self.cap <= 0:
            return
        if key in self.key_val:
            self.key_val[key] = value
            self._increase_freq(key)
            return
        if len(self.key_val) >= self.cap:
            evict_key, _ = self.freq_keys[self.min_freq].popitem(last=False)
            del self.key_val[evict_key]
            del self.key_freq[evict_key]
        self.key_val[key] = value
        self.key_freq[key] = 1
        self.freq_keys[1][key] = None
        self.min_freq = 1
    def _increase_freq(self, key):
        freq = self.key_freq[key]
        del self.freq_keys[freq][key]
        if not self.freq_keys[freq]:
            del self.freq_keys[freq]
            if self.min_freq == freq:
                self.min_freq += 1
        self.key_freq[key] = freq + 1
        self.freq_keys[freq+1][key] = None

class MyCircularQueue:
    def __init__(self, k):
        self.q = [None] * k
        self.head = self.tail = -1
        self.size = k
    def enQueue(self, value):
        if self.isFull():
            return False
        if self.isEmpty():
            self.head = 0
        self.tail = (self.tail + 1) % self.size
        self.q[self.tail] = value
        return True
    def deQueue(self):
        if self.isEmpty():
            return False
        if self.head == self.tail:
            self.head = self.tail = -1
        else:
            self.head = (self.head + 1) % self.size
        return True
    def Front(self):
        return -1 if self.isEmpty() else self.q[self.head]
    def Rear(self):
        return -1 if self.isEmpty() else self.q[self.tail]
    def isEmpty(self):
        return self.head == -1
    def isFull(self):
        return (self.tail + 1) % self.size == self.head

def calculate_ii(s):
    stack, num, sign = [], 0, '+'
    for c in s + '+':
        if c.isdigit():
            num = num * 10 + int(c)
        elif c in '+-*/':
            if sign == '+':
                stack.append(num)
            elif sign == '-':
                stack.append(-num)
            elif sign == '*':
                stack.append(stack.pop() * num)
            elif sign == '/':
                stack.append(int(stack.pop() / num))
            sign, num = c, 0
    return sum(stack)

def restore_ip_addresses(s):
    res = []
    def backtrack(start, dots, ip):
        if dots == 4 and start == len(s):
            res.append(ip[:-1])
            return
        if dots > 4 or start >= len(s):
            return
        for i in range(1, 4):
            if start + i > len(s):
                break
            seg = s[start:start+i]
            if (seg[0] != '0' or len(seg) == 1) and 0 <= int(seg) <= 255:
                backtrack(start+i, dots+1, ip + seg + '.')
    backtrack(0, 0, '')
    return res

def exist(board, word):
    rows, cols = len(board), len(board[0])
    def dfs(r, c, idx):
        if idx == len(word):
            return True
        if not (0 <= r < rows and 0 <= c < cols) or board[r][c] != word[idx]:
            return False
        tmp, board[r][c] = board[r][c], '#'
        found = any(dfs(r+dr, c+dc, idx+1) for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)])
        board[r][c] = tmp
        return found
    for i in range(rows):
        for j in range(cols):
            if dfs(i, j, 0):
                return True
    return False

def solve_sudoku(board):
    rows, cols, boxes = [set() for _ in range(9)], [set() for _ in range(9)], [set() for _ in range(9)]
    empty = []
    for i in range(9):
        for j in range(9):
            if board[i][j] != '.':
                val = board[i][j]
                rows[i].add(val); cols[j].add(val); boxes[(i//3)*3 + j//3].add(val)
            else:
                empty.append((i, j))
    def backtrack(idx):
        if idx == len(empty):
            return True
        r, c = empty[idx]
        box_idx = (r//3)*3 + c//3
        for num in map(str, range(1,10)):
            if num not in rows[r] and num not in cols[c] and num not in boxes[box_idx]:
                board[r][c] = num
                rows[r].add(num); cols[c].add(num); boxes[box_idx].add(num)
                if backtrack(idx+1):
                    return True
                board[r][c] = '.'
                rows[r].remove(num); cols[c].remove(num); boxes[box_idx].remove(num)
        return False
    backtrack(0)

def is_valid_sudoku(board):
    seen = set()
    for i in range(9):
        for j in range(9):
            if board[i][j] != '.':
                num = board[i][j]
                if (i, num) in seen or (num, j) in seen or (i//3, j//3, num) in seen:
                    return False
                seen.add((i, num))
                seen.add((num, j))
                seen.add((i//3, j//3, num))
    return True

def calc_equation(equations, values, queries):
    from collections import defaultdict
    graph = defaultdict(dict)
    for (a, b), v in zip(equations, values):
        graph[a][b] = v
        graph[b][a] = 1 / v
    def dfs(start, end, visited):
        if start not in graph or end not in graph:
            return -1.0
        if start == end:
            return 1.0
        visited.add(start)
        for nb in graph[start]:
            if nb not in visited:
                res = dfs(nb, end, visited)
                if res != -1.0:
                    return res * graph[start][nb]
        return -1.0
    ans = []
    for a, b in queries:
        ans.append(dfs(a, b, set()))
    return ans

def find_celebrity(n, knows):
    candidate = 0
    for i in range(1, n):
        if knows(candidate, i):
            candidate = i
    for i in range(n):
        if i != candidate and (knows(candidate, i) or not knows(i, candidate)):
            return -1
    return candidate

def find_redundant_connection(edges):
    parent = list(range(len(edges)+1))
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]
    for u, v in edges:
        ru, rv = find(u), find(v)
        if ru == rv:
            return [u, v]
        parent[ru] = rv

def max_path_sum(root):
    self.max_sum = float('-inf')
    def max_gain(node):
        if not node:
            return 0
        left_gain = max(max_gain(node.left), 0)
        right_gain = max(max_gain(node.right), 0)
        self.max_sum = max(self.max_sum, node.val + left_gain + right_gain)
        return node.val + max(left_gain, right_gain)
    max_gain(root)
    return self.max_sum

def count_numbers_with_unique_digits(n):
    if n == 0:
        return 1
    ans, base = 10, 9
