def fraction_to_decimal(numerator, denominator):
    if numerator == 0:
        return '0'
    res = []
    if (numerator < 0) ^ (denominator < 0):
        res.append('-')
    num, den = abs(numerator), abs(denominator)
    integer, num = divmod(num, den)
    res.append(str(integer))
    if num == 0:
        return ''.join(res)
    res.append('.')
    seen = {}
    while num:
        if num in seen:
            res.insert(seen[num], '(')
            res.append(')')
            break
        seen[num] = len(res)
        num *= 10
        digit, num = divmod(num, den)
        res.append(str(digit))
    return ''.join(res)

