    return '/' + '/'.join(stack)

def is_number(s):
    s = s.strip()
    seen_digit, seen_dot, seen_e = False, False, False
    for i, c in enumerate(s):
        if c in '+-':
            if i > 0 and s[i-1] not in 'eE':
                return False
        elif c == '.':
            if seen_dot or seen_e:
                return False
            seen_dot = True
        elif c in 'eE':
            if seen_e or not seen_digit:
                return False
            seen_e = True
            seen_digit = False
        elif c.isdigit():
            seen_digit = True
        else:
            return False
    return seen_digit

def full_justify(words, maxWidth):
    res, cur, num_of_letters = [], [], 0
    for w in words:
        if num_of_letters + len(w) + len(cur) > maxWidth:
            for i in range(maxWidth - num_of_letters):
                cur[i % (len(cur)-1 or 1)] += ' '
            res.append(''.join(cur))
            cur, num_of_letters = [], 0
        cur.append(w)
        num_of_letters += len(w)
    res.append(' '.join(cur).ljust(maxWidth))
    return res

def ladder_length(beginWord, endWord, wordList):
    wordSet = set(wordList)
    if endWord not in wordSet:
        return 0
    queue = [(beginWord, 1)]
    while queue:
        word, length = queue.pop(0)
        if word == endWord:
            return length
        for i in range(len(word)):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                nxt = word[:i] + c + word[i+1:]
                if nxt in wordSet:
                    wordSet.remove(nxt)
                    queue.append((nxt, length+1))
    return 0

def open_lock(deadends, target):
    dead = set(deadends)
    if '0000' in dead:
        return -1
    q = [('0000', 0)]
    visited = {'0000'}
    while q:
        node, step = q.pop(0)
        if node == target:
            return step
        for i in range(4):
            for d in (-1, 1):
                nxt = node[:i] + str((int(node[i]) + d) % 10) + node[i+1:]
                if nxt not in visited and nxt not in dead:
                    visited.add(nxt)
                    q.append((nxt, step+1))
    return -1

def min_mutation(start, end, bank):
    bank = set(bank)
    if end not in bank:
        return -1
    q = [(start, 0)]
    while q:
        gene, step = q.pop(0)
        if gene == end:
            return step
        for i in range(len(gene)):
            for c in 'ACGT':
                if c != gene[i]:
                    nxt = gene[:i] + c + gene[i+1:]
                    if nxt in bank:
                        bank.remove(nxt)
                        q.append((nxt, step+1))
    return -1

def connect_ii(root):
    head = root
    while head:
        dummy = Node(0)
        tail = dummy
        cur = head
        while cur:
            if cur.left:
                tail.next = cur.left
                tail = tail.next
            if cur.right:
                tail.next = cur.right
                tail = tail.next
            cur = cur.next
        head = dummy.next
    return root

def num_islands(grid):
    if not grid:
        return 0
    rows, cols = len(grid), len(grid[0])
    def dfs(r, c):
        if 0 <= r < rows and 0 <= c < cols and grid[r][c] == '1':
            grid[r][c] = '0'
            list(map(dfs, (r+1,r-1,r,r), (c,c,c+1,c-1)))
    count = 0
    for i in range(rows):
        for j in range(cols):
            if grid[i][j] == '1':
                dfs(i, j)
                count += 1
    return count

def longest_consecutive(nums):
    num_set = set(nums)
    max_len = 0
    for n in num_set:
        if n - 1 not in num_set:
            cur = n
            cur_len = 1
            while cur + 1 in num_set:
                cur += 1
                cur_len += 1
            max_len = max(max_len, cur_len)
    return max_len

def kmp_search(text, pattern):
    if not pattern:
        return 0
    lps = [0] * len(pattern)
    j = 0
    for i in range(1, len(pattern)):
        while j > 0 and pattern[i] != pattern[j]:
            j = lps[j-1]
        if pattern[i] == pattern[j]:
            j += 1
            lps[i] = j
    j = 0
    for i, c in enumerate(text):
        while j > 0 and c != pattern[j]:
            j = lps[j-1]
        if c == pattern[j]:
            j += 1
        if j == len(pattern):
            return i - j + 1
    return -1

def rabin_karp(text, pattern):
    n, m = len(text), len(pattern)
    if m > n:
        return -1
    base, mod = 256, 101
    h_pattern = h_win = 0
    for i in range(m):
        h_pattern = (h_pattern * base + ord(pattern[i])) % mod
        h_win = (h_win * base + ord(text[i])) % mod
    pow_base = base**(m-1) % mod
    for i in range(n - m + 1):
        if h_pattern == h_win and text[i:i+m] == pattern:
            return i
        if i < n - m:
            h_win = ((h_win - ord(text[i]) * pow_base) * base + ord(text[i+m])) % mod
            h_win %= mod
    return -1

def edit_distance_dp(word1, word2):
    m, n = len(word1), len(word2)
    dp = list(range(n+1))
    for i in range(1, m+1):
        prev, dp[0] = dp[0], i
        for j in range(1, n+1):
            temp = dp[j]
            if word1[i-1] == word2[j-1]:
                dp[j] = prev
            else:
                dp[j] = 1 + min(dp[j-1], dp[j], prev)
            prev = temp
    return dp[-1]

